export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "01:55。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保安室外。行政走廊。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站起來的時候，腿還有點麻。她在販賣機旁坐了太久。琴音的聲音還黏在耳朵裡。「那個人的。」三個字。她甩不掉。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沿著允許通行的走廊走。不是闖禁區。只是站不住。只是需要動。等候區的椅子太硬。燈光太亮。琴音的通話記錄太刺眼。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊轉角傳來輪子壓過地板的聲音。很輕。很平穩。像推車。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停下來。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個穿制服的醫院保安推著一輛推車從走廊另一側過來。推車上有一只箱子。不透明。深灰色的硬殼。上面貼著封條。封條比她之前在急診臨時保管區看到的更完整——邊緣沒有翹起，編號欄位都填了。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯WCE-07。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "箱側的標籤。白色。印著字。她瞇起眼睛。距離有點遠。但她認得那個編號開頭。和她在急診走廊門縫裡看到的是同一串。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯同一只袋子。不，不是袋子了。是箱子。袋子被裝進去了。或者袋子被換成了箱子。不管哪種——它從保安室的暫存，被推進了另一層流程。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往前走了兩步。沒有擋在推車前面。只是站到走廊邊。讓自己被看見。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "那是千田先生的東西嗎？", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保安停了一下推車。看了她一眼。表情沒有變化。沒有懷疑。沒有為難。就是一個在值夜班的人看到有人問話。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.HospitalSecurity, character: "醫院保安", dialogue: "交通案件關聯物。正式確認前不能回答。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音很平。像在念流程手冊裡的一行字。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "可以確認裡面的物品嗎？", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.HospitalSecurity, character: "醫院保安", dialogue: "非家屬、非警方不能確認。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩句話。兩道門。都很禮貌。都很硬。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯非家屬。非警方。我不是家屬。我不是警方。我是目擊者。目擊者在這個流程裡沒有位置。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的視線落在推車側面夾著的一張交接單上。單子被風扇的氣流吹得微微翹起一角。她只看見幾個字。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯私物一式。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四個字。印在品名欄裡。很籠統。籠統到可以裝下任何東西。一件外套。一個貼身小包。一張卡片。一片薄薄的、硬的、邊緣會反光的金屬。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯私物一式。不是「銀色外殼」。不是「資料匣」。不是「金屬片狀物」。是「私物一式」。四個字。把所有東西吞進去。就算外殼真的在裡面——也不會有人承認那是千田冒死要交出的東西。它只是一份私物。一式。沒有名字。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊另一端走來一個人。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是醫護。不是警察。不是穿制服的保安。是一個穿深色防寒外套的人。中等身形。拉鏈拉到胸口。看起來像交通公司安全部門的人。也像警方文職。也像醫院保安的行政協力。哪一種都成立。哪一種都不奇怪。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個人走到推車旁邊。和保安短暫交談了幾句。聲音壓得很低。澪只聽見「確認」「簽收」一類的詞。沒有陰謀的語氣。沒有緊張。像在辦一件普通的夜間交接。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個人從外套內袋掏出一張證件。在保安面前晃了一下。很快。澪只看見證件套上閃過兩個字。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯安全。或者交通。只看到一個詞。另一個被手指擋住了。或者被光線吃掉了。來不及。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保安點頭。把交接單遞過去。那個人接過來，在簽名欄上簽了名字。筆跡很普通。沒有猶豫。像簽過很多次這種單子的人。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "簽完。保安把單子收進夾子。那個人朝推車點了一下頭，轉身往走廊另一端走了。沒有回頭。沒有多看澪一眼。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是黑衣人。不是反派。只是一個在值夜班的人。簽了一張單子。然後走了。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這才是可怕的地方。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保安重新推起推車。輪子壓過地板。很輕。很平穩。推車轉向走廊盡頭的轉角。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在原地。沒有追。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯追上去能怎樣。我不是家屬。我不是警方。我沒有資格攔一只交通案件關聯物交接箱。我攔了——就是「妨礙公務」。就是「可疑人物」。就是親手把自己變成下一個問題。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "推車消失在轉角。輪子的聲音漸漸沒了。走廊恢復安靜。燈光還是那麼亮。地板還是反著光。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯薄硬反光。看不到了。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪。外殼在我手上。被拍下來。被整理成「持尖銳物者」。至少它還在我眼前。至少我還能看見它。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這一輪。它在一只不透明的箱子裡。被推過轉角。被簽進「私物一式」。我連看都看不到了。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她退到走廊邊。靠著牆。牆面涼的。透過外套傳到背上。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從內袋摸出那張紙。攤開。摺痕已經很多了。她找到一塊空白的地方。用指甲壓。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯薄硬反光：不再可見。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯可能仍在箱中。也可能已不在。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯最可怕的是，現在沒有人需要回答我。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把紙摺起來。塞回內袋。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊空了。推車走了。簽字的人走了。保安回到保安室裡。門關上了。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有人搶。沒有人跑。沒有人拔槍。沒有人威脅她。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只是有人把一只箱子推過轉角。簽了一張單子。真相就離她遠了一層。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪。外殼被畫面定義。第二輪。外殼被流程吞掉。兩次都不是被搶走的。兩次都是被改成了我看不懂、也無權質疑的格式。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在走廊中間。背後是關上的保安室門。前方是空掉的轉角。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我救下了第七車裡的千田。但那個東西——他拼命要交給我的東西——正在一層一層地離開我。", background: Background.Chapter_8_Ch8_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "販賣機的方向傳來馬達的嗡嗡聲。很遠。很持續。像什麼都沒發生過。", background: Background.Chapter_8_Ch8_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉身走回等候區。沒有別的地方可以去。", background: Background.Chapter_8_Ch8_Act5_S0 },
];
